# Let's use the full symbol table from the debug file for more accurate resolution
python3 << 'PYEOF'
import subprocess

# Get ALL symbols (including local) from the debug file
result = subprocess.run(
    ['aarch64-linux-gnu-nm', '--defined-only', '/tmp/libmonosgen-2.0.so.debug'],
    capture_output=True, text=True
)

symbols = []
for line in result.stdout.strip().split('\n'):
    parts = line.strip().split(None, 2)
    if len(parts) >= 3 and parts[1].lower() in ('t', 'w'):
        addr = int(parts[0], 16)
        name = parts[2]
        symbols.append((addr, name))

symbols.sort(key=lambda x: x[0])

def lookup(pc):
    best = None
    for i, (addr, name) in enumerate(symbols):
        if addr <= pc:
            best = (addr, name, i)
        else:
            break
    if best:
        offset = pc - best[0]
        # Also get size hint from next symbol
        next_addr = symbols[best[2]+1][0] if best[2]+1 < len(symbols) else 0
        return f"{best[1]}+0x{offset:x}"
    return "???"

addresses = {
    "Thread 7020 (main, tid:7020)": [
        (0x222098, "#01"),
        (0x2241ac, "#02"),
        (0x1abc80, "#03"),
        (0x16de04, "#04"),
    ],
    "Thread 7046 (SGen worker, tid:7046)": [
        (0x2f4b20, "#02"),
        (0x2f4c84, "#03"),
    ],
    "Thread 7048 (Finalizer, tid:7048)": [
        (0x2c1a40, "#02"),
    ],
}

for thread, addrs in addresses.items():
    print(f"\n{thread}:")
    for pc, frame in addrs:
        sym = lookup(pc)
        print(f"  {frame} pc 0x{pc:08x}  libmonosgen-2.0.so  →  {sym}")

PYEOF

